import os
import subprocess

def backup_directory(directory, format):
    if format == "tar.gz":
        command = ["tar", "-czf", f"{directory}.tar.gz", directory]
    elif format == "tar.bz2":
        command = ["tar", "-cjf", f"{directory}.tar.bz2", directory]
    elif format == "zip":
        command = ["zip", "-r", f"{directory}.zip", directory]
    elif format == "7z":
        command = ["7z", "a", f"{directory}.7z", directory]
    else:
        raise ValueError(f"Invalid compression format: {format}")

    subprocess.run(command, check=True)